class Solution {
public:
    int maxSubstrings(string word) {
        int count = 0;
        char lastChar = word[0];
        int startIndex = 0;
        for (int i = 1; i < word.size(); ++i) {
            if (word[i] == lastChar && i - startIndex >= 3) {
                count++;
                startIndex = i + 1;
                if (i + 1 < word.size()) {
                    lastChar = word[i + 1];
                }
            }
        }
        return count;
    }
};
